return items.map(item => {
  const timestamp = new Date().toISOString();
  const message = `[${timestamp}] Focus Session Completed\nStudent: ${item.json.studentId}\nSession ID: ${item.json.sessionId}\nCoins Earned: ${item.json.coinsEarned}\nStreak: ${item.json.streak}`;
  return {
    json: {
      level: 'info',
      message: message,
      metadata: {
        sessionId: item.json.sessionId,
        studentId: item.json.studentId,
        coinsEarned: item.json.coinsEarned,
        streak: item.json.streak,
        timestamp: timestamp
      }
    }
  };
});
